SELECT campaigns.name AS Campaign_Name, users.username AS Manager_Username
FROM campaigns
INNER JOIN users ON campaigns.manager_id = users.user_id;

SELECT LOG(SUM(negatives)) AS Log_Total_Negative_Responses
FROM campaign_results
WHERE negatives > 0;

SELECT name, budget
FROM campaigns
WHERE status IN ('completed', 'cancelled');

SELECT * 
FROM campaigns 
WHERE expected_revenue = (
    SELECT MAX(expected_revenue) 
    FROM campaigns
);
